import{_ as t,o as e,c as a,ag as l}from"./chunks/framework.DtEl18Xn.js";const o="/getbiji-docs-v3/images/J62ObaThqoMobExiiKzcvE0Rnne.png",p="/getbiji-docs-v3/images/IxYEbg9OEo4pQ7xXtjCcDHxgn8L.png",s="/getbiji-docs-v3/images/VSY3bHTYEoHzQ8xKiLxcfqkpnMb.png",r="/getbiji-docs-v3/images/V217bylFJouExzxGbJhchIuZnwd.png",u=JSON.parse('{"title":"AI柳比歇夫记日记","description":"","frontmatter":{"title":"AI柳比歇夫记日记","category":"GetSeed AI录音卡","lastUpdated":"2026-03-14T15:00:12.015Z"},"headers":[],"relativePath":"getseed-ai录音卡/ai柳比歇夫记日记.md","filePath":"getseed-ai录音卡/ai柳比歇夫记日记.md"}'),n={name:"getseed-ai录音卡/ai柳比歇夫记日记.md"};function _(c,i,d,g,A,m){return e(),a("div",null,[...i[0]||(i[0]=[l('<h1 id="ai柳比歇夫记日记" tabindex="-1">AI柳比歇夫记日记 <a class="header-anchor" href="#ai柳比歇夫记日记" aria-label="Permalink to &quot;AI柳比歇夫记日记&quot;">​</a></h1><p>**AI柳比歇夫记日记——让 AI 帮你把每一天原原本本记下来 **</p><p>**不用动手写，不怕忘记录，AI 自动帮你生成每日日记 **</p><p>柳比歇夫用分钟为单位记录时间，坚持了 56 年；马伯庸每天手动记十几条日记，只写客观事实不写感慨。他们证明了一件事：忠实记录自己，是一项有巨大回报的投资。但普通人坚持不下来，不是不够自律，而是记录的成本太高。现在，AI 柳比歇夫帮你解决这个问题——你只需正常生活、正常工作，AI 自动把你的一天整理成一份客观、忠实的日记。</p><p>**为什么要记这样的日记？ **</p><p>不写感悟、不发感慨，只记录客观事实。今天做了什么、每件事花了多久、有哪些值得记住的细节——就像柳比歇夫那样，原原本本记下发生的一切。看起来平淡无奇，但当这些记录积累起来，你会发现惊人的价值：你以为自己每天工作 8 小时，实际深度工作可能只有 3 小时；你以为自己是夜猫子，数据却告诉你早上才是黄金时间；你以为那个重要想法是在会议室冒出来的，回看记录才发现是跑步时想通的。看得见的东西才能被管理，被管理的东西才能被优化。</p><p><strong>适用场景</strong></p><ul><li>日常工作：AI 自动记录你参加了什么会、讨论了什么主题、发言了几次、花了多长时间，不用你手动整理</li><li>学习成长：听课、读书、听播客，你接触的知识和冒出的想法都被自动记下来，形成个人成长轨迹</li><li>灵感捕捉：通勤路上、散步发呆时冒出的念头，按一下 Mark 键告诉 AI 你在想什么，日记里就多了一笔</li><li>时间洞察：坚持记录一段时间后，按周、按月、按年回顾，找到自己的时间黑洞和黄金时段</li><li>年度复盘：一年下来，清楚看到哪些事花了最多时间、哪些事不值得投入太多精力，用数据做决策</li><li>生活记录：和朋友聊天、陪家人相处、独处思考，AI 记录的不只是&quot;会议室里的你&quot;，而是完整的你</li></ul><p><strong>核心功能</strong></p><ul><li>自动生成日记：录音卡笔记生成后，AI 柳比歇夫自动从中提取信息，整理进当天日记，无需手动操作</li><li>客观忠实记录：只叙述不评价，记录你做了什么、花了多久、有哪些关键细节</li><li>对话式补充：随时和 AI 柳比歇夫对话，补充、修改或更新日记内容，想到什么说一句就行</li><li>长期积累洞察：日记内容可按周、按月、按年进行总结和分析，帮你发现自己没察觉的时间模式和行为规律</li><li>声纹联动：结合声纹识别功能，AI 能在多人场景中精准识别你的声音，准确记录&quot;你&quot;的一天</li></ul><h1 id="app端——使用说明" tabindex="-1"><strong>APP端——使用说明</strong> <a class="header-anchor" href="#app端——使用说明" aria-label="Permalink to &quot;**APP端——使用说明**&quot;">​</a></h1><ol><li>将 Get笔记 App 升级到 2.6.2 及以上版本（<em>AI 柳比歇夫目前仅对 GetSeed 录音卡用户开放，未来会扩大使用范围）</em></li><li>升级后首次进入，GetSeed 录音卡用户会看到引导说明弹窗，跟随引导了解功能详情</li><li>在「GetSeed 录音卡」页面，底部助手区域点击「AI 柳比歇夫记日记」入口，即可进入对话页面</li><li>日常使用录音卡录音，录音完成后连接 App 会自动上传录音文件并生成笔记，AI 柳比歇夫会自动从笔记中提取信息，整理进当天的日记</li><li>你也可以随时通过对话方式，让 AI 柳比歇夫帮你补充或更新日记内容——比如告诉它「下午去跑了��小时步」，它就会帮你记上</li></ol><p><img src="'+o+'" alt=""></p><p><img src="'+p+'" alt=""></p><p><img src="'+s+'" alt=""></p><p><img src="'+r+'" alt=""></p>',16)])])}const b=t(n,[["render",_]]);export{u as __pageData,b as default};
